import 'package:flutter/material.dart';

class ParentWidget extends StatefulWidget {
  @override
  State<ParentWidget> createState() => _ParentWidgetState();
}

class _ParentWidgetState extends State<ParentWidget> {
  String status = 'Inactive';

  @override
  Widget build(BuildContext context) {
    return Column(
      children: [
        Text(status),
        ChildButton(onToggle: () => setState(() => status = 'Active')),
      ],
    );
  }
}

class ChildButton extends StatelessWidget {
  final VoidCallback onToggle;
  const ChildButton({required this.onToggle});
  @override
  Widget build(BuildContext context) => ElevatedButton(onPressed: onToggle, child: const Text('Change'));
}
